mapper.select:
SELECT 
FROM sys_attendance a
WHERE a.id = #{id}

SELECT 
FROM sys_attendance a
WHERE a.emp_id = #{empId} AND a.attendance_date = #{attendanceDate}

SELECT ,
       e.emp_name, e.emp_no, d.dept_name
FROM sys_attendance a
LEFT JOIN sys_emp e ON a.emp_id = e.id
LEFT JOIN sys_dept d ON e.dept_id = d.id


        AND a.emp_id = #{empId}


        AND e.emp_name LIKE CONCAT('%', #{empName}, '%')


        AND a.attendance_date = #{attendanceDate}


         AND a.attendance_date >= #{startDate} 


         AND a.attendance_date <= #{endDate} 


        AND a.status = #{status}


ORDER BY a.attendance_date DESC, a.check_in_time DESC

SELECT 
FROM sys_attendance a
WHERE a.emp_id = #{empId}
AND YEAR(a.attendance_date) = #{year}
AND MONTH(a.attendance_date) = #{month}
ORDER BY a.attendance_date DESC

