UPDATE sys_attendance
check_in_time = #{checkInTime}, check_out_time = #{checkOutTime}, work_hours = #{workHours}, status = #{status}, check_in_location = #{checkInLocation}, check_out_location = #{checkOutLocation},
WHERE id = #{id}
